function renderCitedResponse(rawText, sources) {
  const sourceMap = Object.fromEntries(sources.map(s => [s.index, s]));

  // Replace [N] with superscript links
  const cited = rawText.replace(/\[(\d+)\]/g, (_, n) => {
    const source = sourceMap[parseInt(n)];
    if (!source) return `[${n}]`;
    return (
      `<a href="${escapeAttr(source.url)}" ` +
      `target="_blank" rel="noopener noreferrer" ` +
      `class="citation" title="${escapeAttr(source.title)}">[${n}]</a>`
    );
  });

  // Build reference list (only cited sources)
  const usedIndices = [...rawText.matchAll(/\[(\d+)\]/g)]
    .map(m => parseInt(m[1]))
    .filter((v, i, a) => a.indexOf(v) === i)
    .sort((a, b) => a - b);

  const refs = usedIndices
    .filter(n => sourceMap[n])
    .map(n => {
      const s = sourceMap[n];
      return `<li id="ref-${n}"><a href="${escapeAttr(s.url)}" target="_blank" rel="noopener">${escapeHtml(s.title)}</a></li>`;
    })
    .join("");

  const refList = refs
    ? `<div class="references"><h4>Sources</h4><ol>${refs}</ol></div>`
    : "";

  return `<div class="response">${marked.parse(cited)}</div>${refList}`;
}

function escapeAttr(str) {
  return str.replace(/"/g, "&quot;").replace(/'/g, "&#39;");
}
function escapeHtml(str) {
  return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

