# Tool that returns pre-structured citations
SEARCH_WITH_CITATIONS = {
    "name": "search_knowledge_base",
    "description": "Search the knowledge base and return cited passages",
    "input_schema": {
        "type": "object",
        "properties": {
            "query": {"type": "string"},
            "max_results": {"type": "integer", "default": 5},
        },
        "required": ["query"],
    },
}

async def search_and_answer_with_citations(
    question: str,
    pool,  # database pool
) -> dict:
    messages = [{"role": "user", "content": question}]
    source_map: dict[int, dict] = {}
    source_counter = [0]

    def make_tool_result(query: str) -> str:
        results = sync_search(pool, query, limit=5)
        items = []
        for r in results:
            source_counter[0] += 1
            idx = source_counter[0]
            source_map[idx] = {"url": r["source_url"], "title": r["title"]}
            items.append(f"[{idx}] {r['title']}:\n{r['content'][:400]}")
        return "\n\n".join(items)

    # Agentic loop (simplified)
    while True:
        response = client.messages.create(
            model="claude-sonnet-5",
            max_tokens=2048,
            system=(
                "Cite all information from the search results using [N] markers. "
                "Every factual claim needs a citation."
            ),
            messages=messages,
            tools=[SEARCH_WITH_CITATIONS],
        )

        if response.stop_reason == "end_turn":
            answer = next(b.text for b in response.content if b.type == "text")
            return {"answer": answer, "sources": source_map}

        messages.append({"role": "assistant", "content": response.content})
        tool_results = []
        for block in response.content:
            if block.type == "tool_use" and block.name == "search_knowledge_base":
                content = make_tool_result(block.input["query"])
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": content,
                })
        messages.append({"role": "user", "content": tool_results})

from dataclasses import dataclass, field

@dataclass
class CitationTracker:
    sources: list[dict] = field(default_factory=list)
    _counter: int = 0

    def add_results(self, tool_output: list[dict]) -> str:
        """
        Register results from one search round.
        Returns the numbered context string to inject into the next user message.
        """
        lines = []
        for item in tool_output:
            self._counter += 1
            idx = self._counter
            self.sources.append({
                "index": idx,
                "url": item.get("url", ""),
                "title": item.get("title", f"Source {idx}"),
            })
            snippet = item.get("snippet", "")[:300]
            lines.append(f"[{idx}] {item.get('title', '')}: {snippet}")
        return "\n".join(lines)

    @property
    def available_indices(self) -> set[int]:
        return {s["index"] for s in self.sources}

    def get_used_sources(self, answer: str) -> list[dict]:
        import re
        cited_indices = {int(m) for m in re.findall(r'\[(\d+)\]', answer)}
        return [s for s in self.sources if s["index"] in cited_indices]

