import re, pytest

def test_citations_present_when_sources_provided():
    search_results = [
        {"url": "https://example.com/1", "title": "Source 1", "snippet": "Paris is the capital."},
        {"url": "https://example.com/2", "title": "Source 2", "snippet": "France is in Europe."},
    ]
    result = answer_with_citations("What is the capital of France?", search_results)
    assert re.search(r'\[\d+\]', result["answer"]), "Expected at least one citation marker"

def test_no_hallucinated_citations():
    search_results = [{"url": "https://example.com/1", "title": "A", "snippet": "The sky is blue."}]
    result = answer_with_citations("Is the sky blue?", search_results)
    available = {s["index"] for s in result["sources"]}
    cited_raw = {int(m) for m in re.findall(r'\[(\d+)\]', result["answer"])}
    hallucinated = cited_raw - available
    assert not hallucinated, f"Hallucinated citation indices: {hallucinated}"

def test_citation_tracker_multi_round():
    tracker = CitationTracker()
    ctx1 = tracker.add_results([
        {"url": "u1", "title": "T1", "snippet": "First result."},
    ])
    ctx2 = tracker.add_results([
        {"url": "u2", "title": "T2", "snippet": "Second result."},
    ])
    # Round 2 should start at index 2, not restart at 1
    assert "[1]" in ctx1
    assert "[2]" in ctx2
    assert tracker._counter == 2

def test_unused_sources_not_in_reference_list():
    search_results = [
        {"url": "https://example.com/1", "title": "A", "snippet": "Relevant info."},
        {"url": "https://example.com/2", "title": "B", "snippet": "Irrelevant info."},
    ]
    result = answer_with_citations("Tell me about A.", search_results)
    used = extract_cited_indices(result["answer"])
    # If only [1] was cited, [2] should not appear in the rendered reference list
    assert len(used) <= 2  # can be 0, 1, or 2
    for idx in used:
        assert idx in {s["index"] for s in result["sources"]}
